/// Read every regular file out of an archive into memory as
/// `(entry_path, contents)`, without extracting to disk.
///
/// Used by per-file GitHub attestation verification: each contained file must be
/// hashed and attested individually. Directories, symlinks, hard links, and
/// other non-regular entries are skipped — GitHub attestations bind to file
/// *content*, which only regular files have. The caller is responsible for
/// treating a non-empty result as authoritative for "every regular member".
///
/// Only tar-family and zip archives are readable here; 7z and non-archive
/// formats return an error so the caller can fall through to other verification
/// paths rather than silently skipping per-file verification.
pub fn archive_regular_file_contents(
    archive: &Path,
    format: TarFormat,
) -> Result<Vec<(String, Vec<u8>)>> {
    match format {
        TarFormat::Zip => read_zip_members(archive),
        TarFormat::SevenZip => bail!(
            "7z archives are not supported for per-file attestation inspection: {}",
            display_path(archive)
        ),
        // open_tar treats the single-file compression formats (Gz/Xz/Bz2/Zst) and
        // Raw as gzip; they are not multi-file archives and are filtered out by
        // callers via TarFormat::is_archive() before reaching here.
        TarFormat::TarGz
        | TarFormat::TarXz
        | TarFormat::TarBz2
        | TarFormat::TarZst
        | TarFormat::Tar
        | TarFormat::Gz
        | TarFormat::Xz
        | TarFormat::Bz2
        | TarFormat::Zst
        | TarFormat::Raw => read_tar_members(archive, format),
    }
}

fn read_tar_members(archive: &Path, format: TarFormat) -> Result<Vec<(String, Vec<u8>)>> {
    let err = || format!("failed to read tar members: {}", display_path(archive));
    let tar = open_tar(format, archive)?;
    let mut tar_archive = Archive::new(tar);
    let mut out = Vec::new();
    for entry in tar_archive.entries().wrap_err_with(err)? {
        let mut entry = entry.wrap_err_with(err)?;
        // is_file() is true only for Regular/Continuous entries; it excludes
        // directories, symlinks, hard links, devices, and fifos.
        if !entry.header().entry_type().is_file() {
            continue;
        }
        let name = entry.path().wrap_err_with(err)?.display().to_string();
        let mut buf = Vec::new();
        entry.read_to_end(&mut buf).wrap_err_with(err)?;
        out.push((name, buf));
    }
    Ok(out)
}

fn read_zip_members(archive: &Path) -> Result<Vec<(String, Vec<u8>)>> {
    let err = || format!("failed to read zip members: {}", display_path(archive));
    let f = File::open(archive).wrap_err_with(err)?;
    let mut zip = ZipArchive::new(f).wrap_err_with(err)?;
    let mut out = Vec::new();
    for i in 0..zip.len() {
        let mut entry = zip.by_index(i).wrap_err_with(err)?;
        if entry.is_dir() {
            continue;
        }
        // Skip symlinks: their "content" is a link target, not attestable bytes.
        // S_IFMT = 0o170000, S_IFLNK = 0o120000.
        if entry.unix_mode().is_some_and(|m| m & 0o170000 == 0o120000) {
            continue;
        }
        let name = entry.name().to_string();
        let mut buf = Vec::new();
        entry.read_to_end(&mut buf).wrap_err_with(err)?;
        out.push((name, buf));
    }
    Ok(out)
}

