async fn try_verify_github_attestations(
    &self,
    ctx: &InstallContext,
    tv: &ToolVersion,
    file_path: &std::path::Path,
    api_url: &str,
) -> std::result::Result<bool, VerificationStatus> {
    ctx.pr
        .set_message("verify GitHub artifact attestations".to_string());

    // Parse owner/repo from the repo string
    let repo = self.repo();
    let parts: Vec<&str> = repo.split('/').collect();
    if parts.len() != 2 {
        return Err(VerificationStatus::Error(format!(
            "Invalid repo format: {repo}"
        )));
    }
    let (owner, repo_name) = (parts[0], parts[1]);

    // Archive-level attestation first; on NoAttestations this transparently
    // falls back to per-file (archive-member) verification, which fails
    // closed on partial/tampered archives and returns Unavailable only when
    // no file is attested at all.
    match crate::github::sigstore::verify_attestation_with_per_file_fallback(
        file_path,
        owner,
        repo_name,
        None,
        Some(api_url),
    )
    .await
    {
        Ok(crate::github::sigstore::AttestationOutcome::Verified) => {
            ctx.pr
                .set_message("✓ GitHub artifact attestations verified".to_string());
            debug!("GitHub artifact attestations verified successfully for {tv}");
            Ok(true)
        }
        Ok(crate::github::sigstore::AttestationOutcome::Unavailable) => {
            Err(VerificationStatus::NoAttestations)
        }
        Err(e) => Err(VerificationStatus::Error(e.to_string())),
    }
}

