    /// Build a tar.gz in a temp file with a mix of entry types for the
    /// `archive_regular_file_contents` tests.
    fn build_mixed_tar_gz(path: &Path) {
        use flate2::write::GzEncoder;
        use flate2::Compression;
        let f = File::create(path).unwrap();
        let enc = GzEncoder::new(f, Compression::default());
        let mut builder = tar::Builder::new(enc);

        fn add_regular(builder: &mut tar::Builder<GzEncoder<File>>, path: &str, data: &[u8]) {
            let mut header = tar::Header::new_gnu();
            header.set_entry_type(tar::EntryType::Regular);
            header.set_path(path).unwrap();
            header.set_size(data.len() as u64);
            header.set_mode(0o644);
            header.set_cksum();
            builder.append(&header, &*data).unwrap();
        }

        add_regular(&mut builder, "dir/binary", b"BINARY");
        add_regular(&mut builder, "README", b"readme");

        // Directory entry — must be skipped.
        let mut dir = tar::Header::new_gnu();
        dir.set_entry_type(tar::EntryType::Directory);
        dir.set_path("dir").unwrap();
        dir.set_size(0);
        dir.set_mode(0o755);
        dir.set_cksum();
        builder.append(&dir, std::io::empty()).unwrap();

        // Symlink entry — must be skipped (no attestable content).
        let mut link = tar::Header::new_gnu();
        link.set_entry_type(tar::EntryType::Symlink);
        link.set_path("link").unwrap();
        link.set_link_name("dir/binary").unwrap();
        link.set_size(0);
        link.set_mode(0o777);
        link.set_cksum();
        builder.append(&link, std::io::empty()).unwrap();

        builder.finish().unwrap();
    }

    #[test]
    fn test_archive_regular_file_contents_tar_gz_only_regular() {
        let tmp = tempfile::tempdir().unwrap();
        let archive_path = tmp.path().join("test.tar.gz");
        build_mixed_tar_gz(&archive_path);

        let mut members = archive_regular_file_contents(&archive_path, TarFormat::TarGz).unwrap();
        members.sort_by(|a, b| a.0.cmp(&b.0));
        assert_eq!(
            members.len(),
            2,
            "directories and symlinks must be excluded: {members:?}"
        );
        assert_eq!(members[0].0, "README");
        assert_eq!(members[0].1, b"readme");
        assert_eq!(members[1].0, "dir/binary");
        assert_eq!(members[1].1, b"BINARY");
    }

    #[test]
    fn test_archive_regular_file_contents_unsupported_format_errors() {
        // 7z is not readable cross-platform; the caller treats this as
        // "per-file verification unavailable" (fall through), never as success.
        let tmp = tempfile::tempdir().unwrap();
        let path = tmp.path().join("x.7z");
        std::fs::write(&path, b"not actually 7z").unwrap();
        assert!(archive_regular_file_contents(&path, TarFormat::SevenZip).is_err());
    }

    #[test]
    fn test_archive_regular_file_contents_zip_only_regular() {
        use zip::write::SimpleFileOptions;
        use zip::ZipWriter;
        let tmp = tempfile::tempdir().unwrap();
        let path = tmp.path().join("test.zip");
        let file = File::create(&path).unwrap();
        let mut zip = ZipWriter::new(file);
        let opts = SimpleFileOptions::default();
        zip.start_file("binary", opts).unwrap();
        zip.write_all(b"BINARY").unwrap();
        zip.start_file("README", opts).unwrap();
        zip.write_all(b"readme").unwrap();
        zip.add_directory("dir/", opts).unwrap();
        zip.finish().unwrap();
        drop(zip);

        let mut members = archive_regular_file_contents(&path, TarFormat::Zip).unwrap();
        members.sort_by(|a, b| a.0.cmp(&b.0));
        assert_eq!(members.len(), 2, "directory entries must be excluded");
        assert_eq!(members[0].0, "README");
        assert_eq!(members[0].1, b"readme");
        assert_eq!(members[1].0, "binary");
        assert_eq!(members[1].1, b"BINARY");
    }
}

