/// Outcome of attempting GitHub attestation verification with the per-file fallback.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum AttestationOutcome {
    /// A valid attestation was verified — either at the archive level, or every
    /// regular file inside the archive was individually attested.
    Verified,
    /// No attestation was found at any granularity (archive blob and every
    /// contained regular file). This is not a failure: the release simply does
    /// not publish GitHub attestations, so the caller should fall through to
    /// other verification mechanisms (SLSA, checksums) just as before.
    Unavailable,
}

/// Verify a GitHub artifact attestation, falling back to per-file verification.
///
/// The existing **archive-level** verification is tried first and its behavior is
/// fully preserved: on success we return [`AttestationOutcome::Verified`].
///
/// Only when the archive blob has *no* attestation (`NoAttestations`) do we
/// attempt the **per-file fallback**: if the artifact is a multi-file archive,
/// each regular file's contents are extracted and required to carry a valid
/// GitHub attestation. This lets mise accept releases that attest each contained
/// file rather than the archive blob.
///
/// Fail-closed policy (security-sensitive): if *any* file is attested but
/// *another* file is not (or fails verification), this returns a hard error — it
/// is treated as evidence of tampering. Only when *no* file is attested at all do
/// we return [`AttestationOutcome::Unavailable`] (fall through to SLSA/checksums,
/// matching prior behavior for non-attested tools). If the archive cannot be
/// inspected (unsupported format, parse error) we also return `Unavailable` —
/// per-file verification can't run, but that is not itself a verification failure.
pub async fn verify_attestation_with_per_file_fallback(
    artifact_path: &Path,
    owner: &str,
    repo: &str,
    expected_workflow: Option<&str>,
    api_url: Option<&str>,
) -> AttestationResult<AttestationOutcome> {
    match verify_attestation(artifact_path, owner, repo, expected_workflow, api_url).await {
        Ok(true) => return Ok(AttestationOutcome::Verified),
        Ok(false) => {
            return Err(AttestationError::Verification(
                "GitHub artifact attestations verification returned false".to_string(),
            ))
        }
        // No attestation on the archive blob — try the per-file fallback.
        Err(AttestationError::NoAttestations) => {}
        Err(e) => return Err(e),
    }

    let format = crate::file::TarFormat::from_file_name(
        &artifact_path
            .file_name()
            .map(|n| n.to_string_lossy().to_string())
            .unwrap_or_default(),
    );
    if !format.is_archive() {
        return Ok(AttestationOutcome::Unavailable);
    }

    // If the archive can't be inspected, per-file verification can't run. Fall
    // through to SLSA/checksums (which operate on the archive blob) rather than
    // turning an unsupported format into a hard failure.
    let members = match crate::file::archive_regular_file_contents(artifact_path, format) {
        Ok(m) => m,
        Err(e) => {
            debug!(
                "skipping per-file attestation fallback, could not read archive members: {e}"
            );
            return Ok(AttestationOutcome::Unavailable);
        }
    };
    if members.is_empty() {
        return Ok(AttestationOutcome::Unavailable);
    }

    let token = resolve_token_for_wrapper(api_url);
    let source = match api_url {
        Some(base_url) => GitHubSource::with_base_url(owner, repo, token.as_deref(), base_url),
        None => GitHubSource::new(owner, repo, token.as_deref()),
    }
    .map_err(|e| AttestationError::Api(format!("failed to build GitHub attestation source: {e}")))?;

    match mise_sigstore::verify_github_attestations_for_files(&members, &source, expected_workflow)
        .await?
    {
        mise_sigstore::PerFileAttestationOutcome::AllVerified { .. } => {
            Ok(AttestationOutcome::Verified)
        }
        mise_sigstore::PerFileAttestationOutcome::NonePresent => {
            Ok(AttestationOutcome::Unavailable)
        }
    }
}

